mapper.select:
select id, task_id, source_sop_instance_uid, related_sop_instance_uid,
       related_type, related_series_instance_uid, orthanc_instance_id,
       evaluation_id, create_time
  from ndt_dicom_object_relation

    and task_id = #{taskId}
    and source_sop_instance_uid = #{sourceSopInstanceUid}
    and related_type = #{relatedType}
    and evaluation_id = #{evaluationId}

order by id desc
